import 'dart:async';

/// Shared socket contract implemented by all Navivox gateway transports.
///
/// Platform transports keep their concrete socket wrappers for compatibility,
/// while this interface names the common stream/send/close behavior they expose.
abstract interface class NavivoxGatewaySocketConnection {
  Stream<dynamic> get events;

  void add(String message);

  Future<void> close();
}

import 'navivox_gateway_socket_contract.dart';

/// Shared HTTP GET transport contract used by the gateway client and tests.
typedef NavivoxGatewayGet =
    Future<String> Function(Uri uri, Map<String, String> headers);

/// Shared HTTP POST transport contract used by the gateway client and tests.
typedef NavivoxGatewayPost =
    Future<String> Function(Uri uri, Map<String, String> headers, String body);

/// Shared WebSocket transport contract decoupled from platform socket wrappers.
typedef NavivoxGatewayWebSocketConnector =
    Future<NavivoxGatewaySocketConnection> Function(
      Uri uri,
      Map<String, String> headers,
    );

/// Shared transport error factories for unsupported gateway platform features.
///
/// Keeping these messages in one contract prevents stub transports from
/// drifting between HTTP and WebSocket entrypoints while preserving the exact
/// UnsupportedError behavior exposed by the compatibility facades.
const navivoxGatewayUnsupportedHttpMessage =
    'Navivox gateway HTTP is not supported here.';

/// Error message used when WebSocket transport is unavailable on a platform.
const navivoxGatewayUnsupportedWebSocketMessage =
    'Navivox gateway WebSocket is not supported here.';

/// Builds the platform-stub HTTP unsupported error.
UnsupportedError navivoxGatewayUnsupportedHttp() {
  return UnsupportedError(navivoxGatewayUnsupportedHttpMessage);
}

/// Builds the platform-stub WebSocket unsupported error.
UnsupportedError navivoxGatewayUnsupportedWebSocket() {
  return UnsupportedError(navivoxGatewayUnsupportedWebSocketMessage);
}

import 'dart:convert';
import 'dart:io';

import '../shared/navivox_gateway_http.dart';
import 'navivox_gateway_socket_contract.dart';

class NavivoxGatewaySocket implements NavivoxGatewaySocketConnection {
  NavivoxGatewaySocket(this._socket);

  final WebSocket _socket;

  @override
  Stream<dynamic> get events => _socket;

  @override
  void add(String message) => _socket.add(message);

  @override
  Future<void> close() => _socket.close();
}

Future<String> defaultGet(Uri uri, Map<String, String> headers) async {
  final client = HttpClient();
  try {
    final request = await client.getUrl(uri);
    headers.forEach(request.headers.set);
    return _readResponse(await request.close(), uri);
  } finally {
    client.close();
  }
}

Future<String> defaultPost(
  Uri uri,
  Map<String, String> headers,
  String body,
) async {
  final client = HttpClient();
  try {
    final request = await client.postUrl(uri);
    headers.forEach(request.headers.set);
    request.add(utf8.encode(body));
    return _readResponse(await request.close(), uri);
  } finally {
    client.close();
  }
}

Future<String> _readResponse(HttpClientResponse response, Uri uri) async {
  final body = await utf8.decoder.bind(response).join();
  if (!navivoxGatewayIsSuccessStatus(response.statusCode)) {
    throw HttpException(
      navivoxGatewayHttpStatusMessage(response.statusCode),
      uri: uri,
    );
  }
  return body;
}

Future<NavivoxGatewaySocket> defaultConnectWebSocket(
  Uri uri,
  Map<String, String> headers,
) async {
  final socket = await WebSocket.connect(uri.toString(), headers: headers);
  return NavivoxGatewaySocket(socket);
}

import 'navivox_gateway_socket_contract.dart';
import 'navivox_gateway_transport_errors.dart';

class NavivoxGatewaySocket implements NavivoxGatewaySocketConnection {
  @override
  Stream<dynamic> get events => const Stream<dynamic>.empty();

  @override
  void add(String message) {
    throw navivoxGatewayUnsupportedWebSocket();
  }

  @override
  Future<void> close() async {}
}

Future<String> defaultGet(Uri uri, Map<String, String> headers) {
  throw navivoxGatewayUnsupportedHttp();
}

Future<String> defaultPost(Uri uri, Map<String, String> headers, String body) {
  throw navivoxGatewayUnsupportedHttp();
}

Future<NavivoxGatewaySocket> defaultConnectWebSocket(
  Uri uri,
  Map<String, String> headers,
) {
  throw navivoxGatewayUnsupportedWebSocket();
}

import 'dart:async';
import 'dart:js_interop';
import 'dart:js_interop_unsafe';

import 'package:web/web.dart' as web;

import '../shared/navivox_gateway_auth.dart';
import '../shared/navivox_gateway_http.dart';
import 'navivox_gateway_socket_contract.dart';

class NavivoxGatewaySocket implements NavivoxGatewaySocketConnection {
  NavivoxGatewaySocket._(this._socket) {
    _socket.onmessage = ((web.MessageEvent event) {
      _events.add((event.data as JSString).toDart);
    }).toJS;
    _socket.onerror = ((web.Event event) {
      _events.addError(StateError('Gateway stream error'));
    }).toJS;
    _socket.onclose = ((web.CloseEvent event) {
      if (!_events.isClosed) unawaited(_events.close());
    }).toJS;
  }

  final web.WebSocket _socket;
  final StreamController<dynamic> _events = StreamController<dynamic>();

  @override
  Stream<dynamic> get events => _events.stream;

  @override
  void add(String message) => _socket.send(message.toJS);

  @override
  Future<void> close() async {
    _socket.close();
    if (!_events.isClosed) await _events.close();
  }
}

Future<String> defaultGet(Uri uri, Map<String, String> headers) async {
  final response = await web.window
      .fetch(
        uri.toString().toJS,
        web.RequestInit(headers: _headersToRecord(headers)),
      )
      .toDart;
  return _readResponse(response);
}

Future<String> defaultPost(
  Uri uri,
  Map<String, String> headers,
  String body,
) async {
  final response = await web.window
      .fetch(
        uri.toString().toJS,
        web.RequestInit(
          method: 'POST',
          headers: _headersToRecord(headers),
          body: body.toJS,
        ),
      )
      .toDart;
  return _readResponse(response);
}

Future<String> _readResponse(web.Response response) async {
  if (!navivoxGatewayIsSuccessStatus(response.status)) {
    throw StateError(navivoxGatewayHttpStatusMessage(response.status));
  }
  final jsText = await response.text().toDart;
  return jsText.toDart;
}

Future<NavivoxGatewaySocket> defaultConnectWebSocket(
  Uri uri,
  Map<String, String> headers,
) async {
  final socket = web.WebSocket(
    uri.toString(),
    navivoxGatewayWebSocketProtocols(
      headers,
    ).map((protocol) => protocol.toJS).toList().toJS,
  );
  final completer = Completer<NavivoxGatewaySocket>();

  socket.onopen = ((web.Event event) {
    if (!completer.isCompleted) {
      completer.complete(NavivoxGatewaySocket._(socket));
    }
  }).toJS;
  socket.onerror = ((web.Event event) {
    if (!completer.isCompleted) {
      completer.completeError(StateError('Navivox gateway WebSocket failed'));
    }
  }).toJS;
  socket.onclose = ((web.CloseEvent event) {
    if (!completer.isCompleted) {
      completer.completeError(StateError('Navivox gateway WebSocket closed'));
    }
  }).toJS;

  return completer.future;
}

JSObject _headersToRecord(Map<String, String> headers) {
  final record = JSObject();
  for (final entry in headers.entries) {
    record.setProperty(entry.key.toJS, entry.value.toJS);
  }
  return record;
}

